// /frontend/src/components/BottomBar.jsx
import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

export default function BottomBar() {
  const nav = useNavigate();
  const loc = useLocation();

  const btn = (label, to, isPrimary = false) => {
    const active = loc.pathname === to;
    return (
      <button
        key={to}
        onClick={() => nav(to)}
        className={[
          "flex-1 mx-1 px-3 py-2 rounded-xl text-sm transition",
          "backdrop-blur-md ring-1",
          active
            ? "bg-purple-600 text-white ring-purple-500"
            : isPrimary
            ? "bg-black/60 text-white ring-white/10 hover:bg-black/70"
            : "bg-black/40 text-white ring-white/10 hover:bg-black/60",
        ].join(" ")}
        title={label}
      >
        {label}
      </button>
    );
  };

  return (
    <nav className="sticky bottom-0 left-0 right-0 px-4 pb-4 pt-2 bg-gradient-to-t from-white via-white/80 to-transparent">
      <div className="max-w-screen-md mx-auto flex items-center">
        {btn("Home", "/")}
        {btn("Radar", "/radar")}
        {btn("Community", "/community")}
        {btn("Settings", "/settings")}
      </div>
    </nav>
  );
}
